use serde::{Deserialize, Serialize};
use serde_json;
use std::io::{self, Read};

// `realcompare` implementation from `realcompare_reference.rs`
pub const LT: &str = "LT";
pub const EQ: &str = "EQ";
pub const GT: &str = "GT";

pub fn realcompare(a: f64, b: f64) -> &'static str {
    let scale = a.abs().max(b.abs());
    if scale == 0.0 {
        return "EQ";
    }
    let eps = 0.5e-5 * scale;
    let diff = a - b;
    if diff > eps {
        "GT"
    } else if diff < -eps {
        "LT"
    } else {
        "EQ"
    }
}

#[derive(Debug, Clone, Copy, PartialEq)]
enum Connector {
    NOTUSED,
    ORR,
    ANDD,
}

impl<'de> Deserialize<'de> for Connector {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: serde::Deserializer<'de>,
    {
        let s = String::deserialize(deserializer)?;
        match s.as_str() {
            "NOTUSED" => Ok(Connector::NOTUSED),
            "ORR" => Ok(Connector::ORR),
            "ANDD" => Ok(Connector::ANDD),
            _ => Err(serde::de::Error::custom(format!(
                "unknown connector type: {}",
                s
            ))),
        }
    }
}

#[derive(Debug, Deserialize)]
struct Parameters {
    #[serde(rename = "LENGTH1")]
    length1: f64,
    #[serde(rename = "RADIUS1")]
    radius1: f64,
    #[serde(rename = "EPSILON")]
    epsilon: f64,
    #[serde(rename = "AREA1")]
    area1: f64,
    #[serde(rename = "Q_PTS")]
    q_pts: usize,
    #[serde(rename = "QUADS")]
    quads: usize,
    #[serde(rename = "DIST")]
    dist: f64,
    #[serde(rename = "N_PTS")]
    n_pts: usize,
    #[serde(rename = "K_PTS")]
    k_pts: usize,
    #[serde(rename = "A_PTS")]
    a_pts: usize,
    #[serde(rename = "B_PTS")]
    b_pts: usize,
    #[serde(rename = "C_PTS")]
    c_pts: usize,
    #[serde(rename = "D_PTS")]
    d_pts: usize,
    #[serde(rename = "E_PTS")]
    e_pts: usize,
    #[serde(rename = "F_PTS")]
    f_pts: usize,
    #[serde(rename = "G_PTS")]
    g_pts: usize,
    #[serde(rename = "LENGTH2")]
    length2: f64,
    #[serde(rename = "RADIUS2")]
    radius2: f64,
    #[serde(rename = "AREA2")]
    area2: f64,
}

#[derive(Debug, Deserialize)]
struct Input {
    numpoints: usize,
    x: Vec<f64>,
    y: Vec<f64>,
    parameters: Parameters,
    lcm: Vec<Vec<Connector>>,
    pum_diag: Vec<bool>,
}

#[derive(Debug, Serialize)]
struct Output {
    cmv: Vec<bool>,
    pum: Vec<Vec<bool>>,
    fuv: Vec<bool>,
    launch: bool,
}

struct Point {
    x: f64,
    y: f64,
}

fn dist_points(p1: &Point, p2: &Point) -> f64 {
    ((p1.x - p2.x).powi(2) + (p1.y - p2.y).powi(2)).sqrt()
}

fn lic1(points: &[Point], length1: f64) -> bool {
    if points.len() < 2 {
        return false;
    }
    for i in 0..points.len() - 1 {
        if realcompare(dist_points(&points[i], &points[i + 1]), length1) == GT {
            return true;
        }
    }
    false
}

fn lic2(points: &[Point], radius1: f64) -> bool {
    if points.len() < 3 {
        return false;
    }
    for i in 0..points.len() - 2 {
        let p1 = &points[i];
        let p2 = &points[i + 1];
        let p3 = &points[i + 2];
        let d12 = dist_points(p1, p2);
        let d13 = dist_points(p1, p3);
        let d23 = dist_points(p2, p3);
        let max_dist = d12.max(d13).max(d23);
        if realcompare(max_dist, 2.0 * radius1) == GT {
            return true;
        }

        let circumradius = (d12 * d13 * d23)
            / (2.0 * ((p1.x * (p2.y - p3.y) + p2.x * (p3.y - p1.y) + p3.x * (p1.y - p2.y)))).abs();
        if realcompare(circumradius, radius1) == GT {
            return true;
        }
    }
    false
}

fn lic3(points: &[Point], epsilon: f64) -> bool {
    if points.len() < 3 {
        return false;
    }
    for i in 0..points.len() - 2 {
        let p1 = &points[i];
        let p2 = &points[i + 1];
        let p3 = &points[i + 2];
        if (p1.x == p2.x && p1.y == p2.y) || (p3.x == p2.x && p3.y == p2.y) {
            continue;
        }
        let a = dist_points(p2, p3);
        let b = dist_points(p1, p3);
        let c = dist_points(p1, p2);
        let angle = ((a.powi(2) + c.powi(2) - b.powi(2)) / (2.0 * a * c)).acos();
        if realcompare(angle, std::f64::consts::PI - epsilon) == LT
            || realcompare(angle, std::f64::consts::PI + epsilon) == GT
        {
            return true;
        }
    }
    false
}

fn lic4(points: &[Point], area1: f64) -> bool {
    if points.len() < 3 {
        return false;
    }
    for i in 0..points.len() - 2 {
        let p1 = &points[i];
        let p2 = &points[i + 1];
        let p3 = &points[i + 2];
        let area =
            0.5 * ((p1.x * (p2.y - p3.y) + p2.x * (p3.y - p1.y) + p3.x * (p1.y - p2.y))).abs();
        if realcompare(area, area1) == GT {
            return true;
        }
    }
    false
}

fn lic5(points: &[Point], q_pts: usize, quads: usize) -> bool {
    if points.len() < q_pts {
        return false;
    }
    for i in 0..=points.len() - q_pts {
        let mut quad_set = std::collections::HashSet::new();
        for j in 0..q_pts {
            let p = &points[i + j];
            let quadrant = if p.x >= 0.0 && p.y >= 0.0 {
                1
            } else if p.x < 0.0 && p.y >= 0.0 {
                2
            } else if p.x <= 0.0 && p.y < 0.0 {
                3
            } else {
                4
            };
            quad_set.insert(quadrant);
        }
        if quad_set.len() > quads {
            return true;
        }
    }
    false
}

fn lic6(points: &[Point]) -> bool {
    if points.len() < 2 {
        return false;
    }
    for i in 0..points.len() - 1 {
        if realcompare(points[i + 1].x, points[i].x) == LT {
            return true;
        }
    }
    false
}

fn lic7(points: &[Point], n_pts: usize, dist: f64) -> bool {
    if points.len() < 3 || points.len() < n_pts {
        return false;
    }
    for i in 0..=points.len() - n_pts {
        let p1 = &points[i];
        let p_last = &points[i + n_pts - 1];
        for j in 1..n_pts - 1 {
            let p_check = &points[i + j];
            let distance = if realcompare(p1.x, p_last.x) == EQ && realcompare(p1.y, p_last.y) == EQ
            {
                dist_points(p1, p_check)
            } else {
                ((p_last.x - p1.x) * (p1.y - p_check.y) - (p1.x - p_check.x) * (p_last.y - p1.y))
                    .abs()
                    / dist_points(p1, p_last)
            };
            if realcompare(distance, dist) == GT {
                return true;
            }
        }
    }
    false
}

fn lic8(points: &[Point], k_pts: usize, length1: f64) -> bool {
    if points.len() < 3 || points.len() < k_pts + 2 {
        return false;
    }
    for i in 0..points.len() - k_pts - 1 {
        let p1 = &points[i];
        let p2 = &points[i + k_pts + 1];
        if realcompare(dist_points(p1, p2), length1) == GT {
            return true;
        }
    }
    false
}

fn lic9(points: &[Point], a_pts: usize, b_pts: usize, radius1: f64) -> bool {
    if points.len() < 5 || points.len() < a_pts + b_pts + 3 {
        return false;
    }
    for i in 0..points.len() - a_pts - b_pts - 2 {
        let p1 = &points[i];
        let p2 = &points[i + a_pts + 1];
        let p3 = &points[i + a_pts + b_pts + 2];
        let d12 = dist_points(p1, p2);
        let d13 = dist_points(p1, p3);
        let d23 = dist_points(p2, p3);
        let max_dist = d12.max(d13).max(d23);
        if realcompare(max_dist, 2.0 * radius1) == GT {
            return true;
        }
        let circumradius = (d12 * d13 * d23)
            / (2.0 * ((p1.x * (p2.y - p3.y) + p2.x * (p3.y - p1.y) + p3.x * (p1.y - p2.y)))).abs();
        if realcompare(circumradius, radius1) == GT {
            return true;
        }
    }
    false
}

fn lic10(
    points: &[Point],
    c_pts: usize,
    d_pts: usize,
    epsilon: f64,
) -> bool {
    if points.len() < 5 || points.len() < c_pts + d_pts + 3 {
        return false;
    }
    for i in 0..points.len() - c_pts - d_pts - 2 {
        let p1 = &points[i];
        let p2 = &points[i + c_pts + 1];
        let p3 = &points[i + c_pts + d_pts + 2];
        if (p1.x == p2.x && p1.y == p2.y) || (p3.x == p2.x && p3.y == p2.y) {
            continue;
        }
        let a = dist_points(p2, p3);
        let b = dist_points(p1, p3);
        let c = dist_points(p1, p2);
        let angle = ((a.powi(2) + c.powi(2) - b.powi(2)) / (2.0 * a * c)).acos();
        if realcompare(angle, std::f64::consts::PI - epsilon) == LT
            || realcompare(angle, std::f64::consts::PI + epsilon) == GT
        {
            return true;
        }
    }
    false
}

fn lic11(points: &[Point], e_pts: usize, f_pts: usize, area1: f64) -> bool {
    if points.len() < 5 || points.len() < e_pts + f_pts + 3 {
        return false;
    }
    for i in 0..points.len() - e_pts - f_pts - 2 {
        let p1 = &points[i];
        let p2 = &points[i + e_pts + 1];
        let p3 = &points[i + e_pts + f_pts + 2];
        let area =
            0.5 * ((p1.x * (p2.y - p3.y) + p2.x * (p3.y - p1.y) + p3.x * (p1.y - p2.y))).abs();
        if realcompare(area, area1) == GT {
            return true;
        }
    }
    false
}

fn lic12(points: &[Point], g_pts: usize) -> bool {
    if points.len() < 3 || points.len() < g_pts + 2 {
        return false;
    }
    for i in 0..points.len() - g_pts - 1 {
        if realcompare(points[i + g_pts + 1].x, points[i].x) == LT {
            return true;
        }
    }
    false
}

fn lic13(
    points: &[Point],
    k_pts: usize,
    length1: f64,
    length2: f64,
) -> bool {
    if points.len() < 3 {
        return false;
    }
    let mut cond1 = false;
    let mut cond2 = false;
    for i in 0..points.len() - k_pts - 1 {
        let p1 = &points[i];
        let p2 = &points[i + k_pts + 1];
        let d = dist_points(p1, p2);
        if realcompare(d, length1) == GT {
            cond1 = true;
        }
        if realcompare(d, length2) == LT {
            cond2 = true;
        }
    }
    cond1 && cond2
}

fn lic14(
    points: &[Point],
    a_pts: usize,
    b_pts: usize,
    radius1: f64,
    radius2: f64,
) -> bool {
    if points.len() < 5 {
        return false;
    }
    let mut cond1 = false;
    let mut cond2 = false;
    for i in 0..points.len() - a_pts - b_pts - 2 {
        let p1 = &points[i];
        let p2 = &points[i + a_pts + 1];
        let p3 = &points[i + a_pts + b_pts + 2];
        let d12 = dist_points(p1, p2);
        let d13 = dist_points(p1, p3);
        let d23 = dist_points(p2, p3);
        let max_dist = d12.max(d13).max(d23);

        let circumradius = if realcompare(
            (2.0 * ((p1.x * (p2.y - p3.y) + p2.x * (p3.y - p1.y) + p3.x * (p1.y - p2.y)))).abs(),
            0.0,
        ) == EQ
        {
            f64::INFINITY
        } else {
            (d12 * d13 * d23)
                / (2.0 * ((p1.x * (p2.y - p3.y) + p2.x * (p3.y - p1.y) + p3.x * (p1.y - p2.y))))
                    .abs()
        };

        if realcompare(max_dist, 2.0 * radius1) == GT || realcompare(circumradius, radius1) == GT {
            cond1 = true;
        }
        if realcompare(max_dist, 2.0 * radius2) != GT && realcompare(circumradius, radius2) != GT {
            cond2 = true;
        }
    }
    cond1 && cond2
}

fn lic15(
    points: &[Point],
    e_pts: usize,
    f_pts: usize,
    area1: f64,
    area2: f64,
) -> bool {
    if points.len() < 5 {
        return false;
    }
    let mut cond1 = false;
    let mut cond2 = false;
    for i in 0..points.len() - e_pts - f_pts - 2 {
        let p1 = &points[i];
        let p2 = &points[i + e_pts + 1];
        let p3 = &points[i + e_pts + f_pts + 2];
        let area =
            0.5 * ((p1.x * (p2.y - p3.y) + p2.x * (p3.y - p1.y) + p3.x * (p1.y - p2.y))).abs();
        if realcompare(area, area1) == GT {
            cond1 = true;
        }
        if realcompare(area, area2) == LT {
            cond2 = true;
        }
    }
    cond1 && cond2
}

fn decide() {
    let mut buffer = String::new();
    io::stdin().read_to_string(&mut buffer).unwrap();
    let input: Input = serde_json::from_str(&buffer).unwrap();

    let points: Vec<Point> = input
        .x
        .iter()
        .zip(input.y.iter())
        .map(|(&x, &y)| Point { x, y })
        .collect();

    let mut cmv = vec![false; 15];
    cmv[0] = lic1(&points, input.parameters.length1);
    cmv[1] = lic2(&points, input.parameters.radius1);
    cmv[2] = lic3(&points, input.parameters.epsilon);
    cmv[3] = lic4(&points, input.parameters.area1);
    cmv[4] = lic5(&points, input.parameters.q_pts, input.parameters.quads);
    cmv[5] = lic6(&points);
    cmv[6] = lic7(&points, input.parameters.n_pts, input.parameters.dist);
    cmv[7] = lic8(&points, input.parameters.k_pts, input.parameters.length1);
    cmv[8] = lic9(
        &points,
        input.parameters.a_pts,
        input.parameters.b_pts,
        input.parameters.radius1,
    );
    cmv[9] = lic10(
        &points,
        input.parameters.c_pts,
        input.parameters.d_pts,
        input.parameters.epsilon,
    );
    cmv[10] = lic11(
        &points,
        input.parameters.e_pts,
        input.parameters.f_pts,
        input.parameters.area1,
    );
    cmv[11] = lic12(&points, input.parameters.g_pts);
    cmv[12] = lic13(
        &points,
        input.parameters.k_pts,
        input.parameters.length1,
        input.parameters.length2,
    );
    cmv[13] = lic14(
        &points,
        input.parameters.a_pts,
        input.parameters.b_pts,
        input.parameters.radius1,
        input.parameters.radius2,
    );
    cmv[14] = lic15(
        &points,
        input.parameters.e_pts,
        input.parameters.f_pts,
        input.parameters.area1,
        input.parameters.area2,
    );

    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
            } else {
                pum[i][j] = match input.lcm[i][j] {
                    Connector::NOTUSED => true,
                    Connector::ANDD => cmv[i] && cmv[j],
                    Connector::ORR => cmv[i] || cmv[j],
                };
            }
        }
    }

    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !input.pum_diag[i] {
            fuv[i] = true;
        } else {
            let mut all_true = true;
            for j in 0..15 {
                if i != j && !pum[i][j] {
                    all_true = false;
                    break;
                }
            }
            fuv[i] = all_true;
        }
    }

    let launch = fuv.iter().all(|&x| x);

    let output = Output {
        cmv,
        pum,
        fuv,
        launch,
    };

    println!("{}", serde_json::to_string(&output).unwrap());
}

fn main() {
    decide();
}
